import React, { createContext, useState, useContext, useEffect } from 'react';

// 1. Context 생성
const AuthContext = createContext(null);

// 2. Provider 컴포넌트 생성
export function AuthProvider({ children }) {
  const [user, setUser] = useState(null); // user 상태 관리

  // 앱이 처음 로드될 때 서버에 사용자 정보를 요청
  useEffect(() => {
    fetch('/api/verifyUser')
      .then((res) => res.json())
      .then((data) => {
        if (data.success) {
          setUser(data.user); // 성공 시 사용자 정보 저장
        }
      })
      .catch(() => {
        setUser(null); // 실패 시 사용자 정보 초기화
      });
  }, []);

  // 로그인 함수
  const login = (userData) => {
    setUser(userData);
  };

  // 로그아웃 함수
  const logout = () => {
    // 서버에 로그아웃 요청을 보낼 수도 있습니다. (예: fetch('/api/logout'))
    setUser(null);
  };

  const value = { user, login, logout };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

// 3. 쉽게 사용할 수 있도록 custom hook 생성
export function useAuth() {
  return useContext(AuthContext);
}
